        <div style={{ marginTop: '2px' }}>
          <div style={{ fontSize: '18px', fontWeight: 900, color: '#0F6E56', letterSpacing: '-0.5px' }}>₹{price.toLocaleString()}</div>
          <div style={{ fontSize: '11px', color: '#cbd5e1', textDecoration: 'line-through' }}>₹{(price * 1.2).toLocaleString(undefined, { maximumFractionDigits: 0 })}</div>
        </div>

        {/* Buttons */}
        <div style={{ marginTop: 'auto', paddingTop: '8px', display: 'flex', flexDirection: 'column', gap: '7px' }}>
          <button
            onClick={() => onViewDetails(product)}
            style={{
              width: '100%', padding: '9px', fontSize: '12px', fontWeight: 700,
              background: 'transparent', color: '#0F6E56', border: '1.5px solid #0F6E56',
              borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center',
              justifyContent: 'center', gap: '5px', transition: 'all 0.2s',
            }}
            onMouseEnter={e => { e.currentTarget.style.background = '#f0fdf9'; }}
            onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; }}
          >
            <Eye size={13} /> View Details
          </button>
          <button
            onClick={handleAdd}
            disabled={product.stockQuantity === 0}
            style={{
              width: '100%', padding: '9px', fontSize: '12px', fontWeight: 700,
              background: addedAnim ? 'linear-gradient(135deg, #059669, #10b981)' : product.stockQuantity === 0 ? '#e2e8f0' : 'linear-gradient(135deg, #0F6E56, #1D9E75)',
              color: product.stockQuantity === 0 ? '#94a3b8' : 'white',
              border: 'none', borderRadius: '12px', cursor: product.stockQuantity === 0 ? 'not-allowed' : 'pointer',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px',
              transition: 'all 0.25s cubic-bezier(0.34,1.56,0.64,1)',
              transform: addedAnim ? 'scale(0.96)' : 'scale(1)',
              boxShadow: addedAnim ? '0 4px 14px rgba(5,150,105,0.5)' : product.stockQuantity === 0 ? 'none' : '0 4px 14px rgba(15,110,86,0.25)',
            }}
          >
            {addedAnim ? <><CheckCircle size={13} />Added!</> : product.stockQuantity === 0 ? 'Out of Stock' : <><ShoppingCart size={13} />Add to Cart</>}
          </button>
        </div>
      </div>
    </div>
  );
};

// ─────────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────────
const ProductsPage = ({
  user, products, cart, searchQuery, setSearchQuery,
  setCurrentPage, handleLogout, addToCart, error, setError,
}) => {
  const [chatOpen, setChatOpen] = useState(false);
  const [chatMessages, setChatMessages] = useState([]);
  const [currentMessage, setCurrentMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatEndRef = useRef(null);

  const [semanticSuggestions, setSemanticSuggestions] = useState([]);
  const [semanticResults, setSemanticResults] = useState([]);
  const [searchLoading, setSearchLoading] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSemanticMode, setIsSemanticMode] = useState(false);
  const debounceTimer = useRef(null);

  const [currentBanner, setCurrentBanner] = useState(0);
  const [detailProduct, setDetailProduct] = useState(null);
  const [viewMode, setViewMode] = useState('grid'); // 'grid' | 'list'

  useEffect(() => { chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [chatMessages, isTyping]);
  useEffect(() => { const t = setInterval(() => setCurrentBanner(p => (p + 1) % 3), 5000); return () => clearInterval(t); }, []);

  useEffect(() => {
    const query = searchQuery.trim();
    if (!query || query.length < 2) { setSemanticSuggestions([]); setShowSuggestions(false); if (!query) { setIsSemanticMode(false); setSemanticResults([]); } return; }
    clearTimeout(debounceTimer.current);
    debounceTimer.current = setTimeout(async () => {
      setSearchLoading(true);
      try {
        const res = await productsAPI.search(query, 6);
        const list = res?.data?.results || [];
        setSemanticSuggestions(list);
        setShowSuggestions(list.length > 0);
      } catch { setSemanticSuggestions([]); } finally { setSearchLoading(false); }
    }, 300);
    return () => clearTimeout(debounceTimer.current);
  }, [searchQuery]);

  const handleFullSearch = useCallback(async (override) => {
    const q = (override || searchQuery).trim();
    if (!q) return;
    setShowSuggestions(false); setSearchLoading(true); setIsSemanticMode(true);
    try {
      const res = await productsAPI.search(q, 20);
      setSemanticResults(res?.data?.results || []);
    } catch { setSemanticResults([]); setError('Search failed.'); setIsSemanticMode(false); }
    finally { setSearchLoading(false); }
  }, [searchQuery]);

  const applyCategory = async (cat) => {
    if (!cat) { setSearchQuery(''); setIsSemanticMode(false); setSemanticResults([]); return; }
    setSearchQuery(cat);
    await handleFullSearch(cat);
  };

  const displayedProducts = isSemanticMode ? semanticResults : (products || []);
  const uniqueCategories = Array.from(new Set((products || []).map(p => getCategoryName(p)).filter(Boolean))).slice(0, 20);

  const sendMessage = async (msg) => {
    const text = (msg || currentMessage).trim();
    if (!text || isTyping) return;
    const userMsg = { role: 'user', content: text };
    setChatMessages(prev => [...prev, userMsg]);
    setCurrentMessage('');
    setIsTyping(true);
    try {
      const userId = user?.id || user?.mongoUserId || user?.Id || '';
      const result = await callAIAgent(text, chatMessages, userId);
      setChatMessages(prev => [...prev, {
        role: 'assistant',
        content: result.response || 'I had trouble understanding that. Please try again.',
        products: result.products || null,
        action: result.action || null,
      }]);
    } catch (err) {
      setChatMessages(prev => [...prev, { role: 'assistant', content: "Sorry, I'm having trouble connecting to the AI service. Please try again." }]);
    } finally { setIsTyping(false); }
  };

  const handleChatAddToCart = (product) => {
    addToCart(product, setError);
    setChatMessages(prev => [...prev, { role: 'assistant', content: `✅ **${product.name}** added to your cart!` }]);
  };

  const banners = [
    { title: 'Summer Sale 2026', subtitle: 'Up to 50% OFF on Electronics', desc: 'Free shipping on orders above ₹999', bg: 'linear-gradient(135deg, #0F6E56 0%, #1D9E75 50%, #38bdf8 100%)', accent: '#a7f3d0' },
    { title: 'New Arrivals', subtitle: 'Latest Smartphones & Gadgets', desc: 'Shop the newest tech at best prices', bg: 'linear-gradient(135deg, #7c3aed 0%, #ec4899 50%, #f97316 100%)', accent: '#fce7f3' },
    { title: 'Special Offer', subtitle: 'Buy 2 Get 1 Free', desc: 'On selected audio & wearables', bg: 'linear-gradient(135deg, #f97316 0%, #fbbf24 50%, #a3e635 100%)', accent: '#fef3c7' },
  ];

  // ── GLOBAL KEYFRAMES ──
  const globalCSS = `
    @keyframes bannerSlide { from { transform: translateX(-${currentBanner * 100}%) } to { transform: translateX(-${currentBanner * 100}%) } }
    @keyframes fadeInUp { from { opacity: 0; transform: translateY(24px) } to { opacity: 1; transform: translateY(0) } }
    @keyframes shimmerBg { 0% { background-position: -200% 0 } 100% { background-position: 200% 0 } }
    @keyframes chatBounce { 0%,100% { transform: translateY(0) } 50% { transform: translateY(-4px) } }
    @keyframes spin { from { transform: rotate(0deg) } to { transform: rotate(360deg) } }
    @keyframes dot1 { 0%,80%,100% { transform: scale(0) } 40% { transform: scale(1) } }
    @keyframes dot2 { 0%,20%,80%,100% { transform: scale(0) } 50% { transform: scale(1) } }
    @keyframes dot3 { 0%,40%,80%,100% { transform: scale(0) } 60% { transform: scale(1) } }
    @keyframes pulseGlow { 0%,100% { box-shadow: 0 0 0 0 rgba(29,158,117,0.4) } 50% { box-shadow: 0 0 0 10px rgba(29,158,117,0) } }
    @keyframes slideIn { from { opacity: 0; transform: translateX(20px) } to { opacity: 1; transform: translateX(0) } }
    .card-enter { animation: fadeInUp 0.4s ease both; }
    .chat-msg-enter { animation: slideIn 0.3s ease both; }
    ::-webkit-scrollbar { width: 5px; height: 5px; }
    ::-webkit-scrollbar-track { background: #f0fdf9; }
    ::-webkit-scrollbar-thumb { background: #6ee7b7; border-radius: 10px; }
  `;

  return (
    <div style={{ minHeight: '100vh', background: '#f8fffc', fontFamily: '"Inter", system-ui, sans-serif' }}>
      <style>{globalCSS}</style>

      {/* ════════════════ HEADER ════════════════ */}
      <header style={{ position: 'sticky', top: 0, zIndex: 40, boxShadow: '0 4px 24px rgba(15,110,86,0.12)' }}>

        {/* Top bar */}
        <div style={{ background: 'linear-gradient(135deg, #062a20 0%, #0a3d2e 100%)' }}>
          <div style={{ maxWidth: '1500px', margin: '0 auto', padding: '10px 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '16px' }}>

            {/* Logo */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer', flexShrink: 0 }}>
              <div style={{ width: '40px', height: '40px', background: 'linear-gradient(135deg, #1D9E75, #38bdf8)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 14px rgba(29,158,117,0.5)', animation: 'chatBounce 3s ease-in-out infinite' }}>
                <ShoppingBag size={18} color="white" />
              </div>
              <div>
                <div style={{ fontSize: '20px', fontWeight: 900, color: 'white', letterSpacing: '-0.5px', lineHeight: 1 }}>ShopAI</div>
                <div style={{ fontSize: '9px', color: '#6ee7b7', fontWeight: 700, letterSpacing: '1px', textTransform: 'uppercase' }}>Marketplace</div>
              </div>
            </div>

            {/* Search – desktop */}
            <div style={{ flex: 1, maxWidth: '700px', display: 'flex', borderRadius: '14px', overflow: 'hidden', boxShadow: '0 4px 20px rgba(0,0,0,0.2)', position: 'relative' }} className="hidden md:flex">
              <select
                style={{ background: 'white', color: '#1a2e2a', padding: '0 14px', fontSize: '13px', border: 'none', outline: 'none', fontWeight: 600, cursor: 'pointer', flexShrink: 0 }}
                onChange={e => applyCategory(e.target.value)}
              >
                <option value="">All Categories</option>
                {uniqueCategories.map((cat, i) => <option key={i} value={cat}>{cat}</option>)}
              </select>

              <div style={{ flex: 1, position: 'relative' }}>
                <input
                  value={searchQuery}
                  onChange={e => { setSearchQuery(e.target.value); if (!e.target.value.trim()) { setIsSemanticMode(false); setSemanticResults([]); } }}
                  onKeyDown={e => { if (e.key === 'Enter') handleFullSearch(); if (e.key === 'Escape') setShowSuggestions(false); }}
                  onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                  onFocus={() => semanticSuggestions.length > 0 && setShowSuggestions(true)}
                  placeholder="Search products... (AI-powered ✨)"
                  style={{ width: '100%', padding: '14px 16px', fontSize: '14px', border: 'none', outline: 'none', color: '#1a2e2a', background: 'white' }}
                />
                {searchLoading && <div style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)' }}><Loader2 size={16} style={{ color: '#1D9E75', animation: 'spin 1s linear infinite' }} /></div>}

                {showSuggestions && semanticSuggestions.length > 0 && (
                  <div style={{ position: 'absolute', top: '100%', left: 0, right: 0, background: 'white', border: '1px solid #a7f3d0', borderRadius: '0 0 16px 16px', boxShadow: '0 20px 50px rgba(15,110,86,0.15)', zIndex: 50, maxHeight: '380px', overflowY: 'auto', marginTop: '2px', animation: 'fadeInUp 0.2s ease' }}>
                    <div style={{ padding: '10px 16px', background: '#f0fdf9', borderBottom: '1px solid #e2f8f4', display: 'flex', alignItems: 'center', gap: '8px' }}>
                      <Sparkles size={13} color="#0F6E56" /><span style={{ fontSize: '12px', fontWeight: 700, color: '#0F6E56' }}>AI Suggestions</span>
                    </div>
                    {semanticSuggestions.map((item, idx) => {
                      const price = getPrice(item);
                      const score = item.score ? `${Math.round(item.score * 100)}%` : '';
                      return (
                        <div key={item.id || idx} onMouseDown={() => { setSearchQuery(item.name); setShowSuggestions(false); handleFullSearch(item.name); }}
                          style={{ padding: '12px 16px', cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid #f8fffc', transition: 'background 0.15s' }}
                          onMouseEnter={e => { e.currentTarget.style.background = '#f0fdf9'; }}
                          onMouseLeave={e => { e.currentTarget.style.background = 'white'; }}
                        >
                          <div>
                            <p style={{ fontSize: '13px', fontWeight: 600, color: '#1a2e2a', margin: '0 0 2px' }}>{item.name}</p>
                            <p style={{ fontSize: '11px', color: '#94a3b8', margin: 0 }}>{item.brand || getCategoryName(item)}</p>
                          </div>
                          <div style={{ textAlign: 'right' }}>
                            <span style={{ fontSize: '14px', fontWeight: 800, color: '#0F6E56' }}>₹{price.toLocaleString()}</span>
                            {score && <p style={{ fontSize: '11px', color: '#94a3b8', margin: '2px 0 0' }}>{score} match</p>}
                          </div>
                        </div>
                      );
                    })}
                    <div onMouseDown={() => { setShowSuggestions(false); handleFullSearch(); }}
                      style={{ padding: '12px 16px', textAlign: 'center', color: '#0F6E56', fontSize: '13px', fontWeight: 700, cursor: 'pointer', borderTop: '1px solid #e2f8f4', transition: 'background 0.15s' }}
                      onMouseEnter={e => { e.currentTarget.style.background = '#f0fdf9'; }}
                      onMouseLeave={e => { e.currentTarget.style.background = 'white'; }}>
                      See all results for "{searchQuery}" →
                    </div>
                  </div>
                )}
              </div>

              <button onClick={() => handleFullSearch()} style={{ background: 'linear-gradient(135deg, #1D9E75, #38bdf8)', padding: '0 22px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', color: 'white', fontSize: '14px', fontWeight: 700, transition: 'all 0.2s' }}
                onMouseEnter={e => { e.currentTarget.style.background = 'linear-gradient(135deg, #0F6E56, #1D9E75)'; }}
                onMouseLeave={e => { e.currentTarget.style.background = 'linear-gradient(135deg, #1D9E75, #38bdf8)'; }}
              >
                <Search size={17} /> Search
              </button>
            </div>

            {/* Right actions */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexShrink: 0 }}>
              <button onClick={() => setCurrentPage('profile')}
                style={{ display: 'flex', alignItems: 'center', gap: '8px', background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.15)', borderRadius: '12px', padding: '8px 14px', cursor: 'pointer', transition: 'all 0.2s', color: 'white' }}
                onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.15)'; }}
                onMouseLeave={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.08)'; }}
              >
                <div style={{ width: '32px', height: '32px', borderRadius: '50%', background: 'linear-gradient(135deg, #1D9E75, #38bdf8)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <UserCircle size={18} color="white" />
                </div>
                <div style={{ display: 'none' }} className="lg-block">
                  <div style={{ fontSize: '10px', color: 'rgba(255,255,255,0.6)', lineHeight: 1 }}>Hello,</div>
                  <div style={{ fontSize: '13px', fontWeight: 700, color: 'white', lineHeight: 1.2 }}>{user?.name || user?.fullName || 'User'}</div>
                </div>
              </button>

              <button onClick={() => setCurrentPage('cart')} style={{ position: 'relative', background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.15)', borderRadius: '12px', padding: '10px 14px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', transition: 'all 0.2s', color: 'white', animation: cart.length > 0 ? 'pulseGlow 2s infinite' : 'none' }}
                onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.15)'; }}
                onMouseLeave={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.08)'; }}
              >
                <div style={{ position: 'relative' }}>
                  <ShoppingCart size={22} color="white" />
                  {cart.length > 0 && (
                    <span style={{ position: 'absolute', top: '-8px', right: '-8px', background: 'linear-gradient(135deg, #f97316, #ef4444)', color: 'white', fontSize: '10px', fontWeight: 800, borderRadius: '50%', width: '18px', height: '18px', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px solid #062a20', animation: 'chatBounce 0.8s ease' }}>
                      {cart.length}
                    </span>
                  )}
                </div>
                <div>
                  <div style={{ fontSize: '10px', color: 'rgba(255,255,255,0.6)', lineHeight: 1 }}>Cart</div>
                  <div style={{ fontSize: '13px', fontWeight: 700, color: 'white', lineHeight: 1.2 }}>₹{cart.reduce((s, i) => s + getPrice(i), 0).toLocaleString()}</div>
                </div>
              </button>
            </div>
          </div>
        </div>

        {/* Nav bar */}
        <div style={{ background: 'linear-gradient(135deg, #0F6E56 0%, #1D9E75 60%, #059669 100%)', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
          <div style={{ maxWidth: '1500px', margin: '0 auto', padding: '0 16px', display: 'flex', alignItems: 'center', gap: '4px', overflowX: 'auto' }}>
            <button onClick={() => applyCategory('')} style={{ display: 'flex', alignItems: 'center', gap: '6px', color: 'white', background: searchQuery === '' ? 'rgba(255,255,255,0.2)' : 'transparent', border: 'none', padding: '12px 16px', borderRadius: '0', cursor: 'pointer', fontSize: '13px', fontWeight: 600, whiteSpace: 'nowrap', transition: 'all 0.2s', borderBottom: searchQuery === '' ? '3px solid white' : '3px solid transparent' }}
              onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.15)'; }}
              onMouseLeave={e => { e.currentTarget.style.background = searchQuery === '' ? 'rgba(255,255,255,0.2)' : 'transparent'; }}
            >
              <Package size={14} /> All Products
            </button>
            {uniqueCategories.slice(0, 8).map((cat, i) => (
              <button key={i} onClick={() => applyCategory(cat)} style={{ color: 'white', background: searchQuery === cat ? 'rgba(255,255,255,0.2)' : 'transparent', border: 'none', padding: '12px 16px', cursor: 'pointer', fontSize: '13px', fontWeight: 600, whiteSpace: 'nowrap', transition: 'all 0.2s', borderBottom: searchQuery === cat ? '3px solid white' : '3px solid transparent' }}
                onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.15)'; }}
                onMouseLeave={e => { e.currentTarget.style.background = searchQuery === cat ? 'rgba(255,255,255,0.2)' : 'transparent'; }}
              >{cat}</button>
            ))}
            <div style={{ marginLeft: 'auto', display: 'flex', gap: '4px' }}>
              <button onClick={() => setChatOpen(true)} style={{ display: 'flex', alignItems: 'center', gap: '6px', color: 'white', background: 'rgba(255,255,255,0.15)', border: '1px solid rgba(255,255,255,0.3)', borderRadius: '20px', padding: '8px 16px', cursor: 'pointer', fontSize: '13px', fontWeight: 700, whiteSpace: 'nowrap', transition: 'all 0.2s' }}>
                <Bot size={14} /> AI Assistant
              </button>
              <button onClick={handleLogout} style={{ color: 'rgba(255,255,255,0.8)', background: 'transparent', border: 'none', padding: '8px 14px', cursor: 'pointer', fontSize: '13px', fontWeight: 600, whiteSpace: 'nowrap', display: 'flex', alignItems: 'center', gap: '5px', borderRadius: '20px', transition: 'all 0.2s' }}
                onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.1)'; }}
                onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; }}
              >
                <LogOut size={14} /> Logout
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Mobile search */}
      <div style={{ display: 'flex', background: 'white', padding: '12px 16px', borderBottom: '1px solid #e2f8f4', boxShadow: '0 2px 8px rgba(15,110,86,0.06)' }} className="md:hidden">
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', gap: '10px', background: '#f0fdf9', borderRadius: '12px', padding: '10px 14px', border: '1px solid #a7f3d0' }}>
          <Search size={16} color="#0F6E56" />
          <input value={searchQuery} onChange={e => { setSearchQuery(e.target.value); if (!e.target.value.trim()) { setIsSemanticMode(false); setSemanticResults([]); } }}
            onKeyDown={e => { if (e.key === 'Enter') handleFullSearch(); }}
            placeholder="Search products (AI-powered)..."
            style={{ flex: 1, background: 'transparent', border: 'none', outline: 'none', fontSize: '14px', color: '#1a2e2a' }}
          />
          {searchLoading && <Loader2 size={15} style={{ color: '#1D9E75', animation: 'spin 1s linear infinite', flexShrink: 0 }} />}
        </div>
      </div>

      {/* ════════════════ MAIN CONTENT ════════════════ */}
      <div style={{ maxWidth: '1500px', margin: '0 auto', padding: '0 16px' }}>

        {error && (
          <div style={{ marginTop: '16px', background: '#fef2f2', border: '1px solid #fca5a5', borderRadius: '12px', padding: '12px 16px', display: 'flex', alignItems: 'center', gap: '10px' }}>
            <span style={{ fontSize: '13px', color: '#dc2626', fontWeight: 600 }}>{error}</span>
          </div>
        )}

        {/* ── HERO BANNER ── */}
        <div style={{ position: 'relative', height: '280px', overflow: 'hidden', marginTop: '20px', marginBottom: '24px', borderRadius: '24px', boxShadow: '0 12px 40px rgba(15,110,86,0.2)' }}>
          <div style={{ position: 'absolute', inset: 0, display: 'flex', transition: 'transform 0.6s cubic-bezier(0.45,0,0.55,1)', transform: `translateX(-${currentBanner * 100}%)` }}>
            {banners.map((b, idx) => (
              <div key={idx} style={{ minWidth: '100%', height: '100%', background: b.bg, position: 'relative', overflow: 'hidden' }}>
                {/* Decorative circles */}
                <div style={{ position: 'absolute', top: '-60px', right: '-60px', width: '280px', height: '280px', borderRadius: '50%', background: 'rgba(255,255,255,0.08)' }} />
                <div style={{ position: 'absolute', bottom: '-40px', right: '200px', width: '160px', height: '160px', borderRadius: '50%', background: 'rgba(255,255,255,0.06)' }} />
                <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '40px 48px', color: 'white' }}>
                  <div style={{ fontSize: '11px', fontWeight: 800, letterSpacing: '2px', textTransform: 'uppercase', marginBottom: '10px', opacity: 0.85, background: 'rgba(255,255,255,0.2)', display: 'inline-block', padding: '4px 12px', borderRadius: '20px', width: 'fit-content' }}>Limited offer</div>
                  <h2 style={{ fontSize: '38px', fontWeight: 900, margin: '0 0 6px', letterSpacing: '-1px', textShadow: '0 2px 12px rgba(0,0,0,0.15)' }}>{b.title}</h2>
                  <p style={{ fontSize: '18px', fontWeight: 600, margin: '0 0 6px', opacity: 0.95 }}>{b.subtitle}</p>
