              style={{
                width: '46px', height: '46px', borderRadius: '14px', border: 'none',
                background: !currentMessage.trim() || isTyping ? '#e2f8f4' : 'linear-gradient(135deg, #0F6E56, #1D9E75)',
                color: !currentMessage.trim() || isTyping ? '#94a3b8' : 'white',
                cursor: !currentMessage.trim() || isTyping ? 'not-allowed' : 'pointer',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                flexShrink: 0, transition: 'all 0.2s',
                boxShadow: !currentMessage.trim() || isTyping ? 'none' : '0 4px 14px rgba(15,110,86,0.35)',
              }}
            >
              {isTyping ? <Loader2 size={18} style={{ animation: 'spin 1s linear infinite' }} /> : <Send size={18} />}
            </button>
          </div>
        </div>
      )}

      {/* Floating chat button */}
      {!chatOpen && (
        <button
          onClick={() => setChatOpen(true)}
          style={{
            position: 'fixed', bottom: '24px', right: '24px',
            width: '64px', height: '64px',
            background: 'linear-gradient(135deg, #0F6E56 0%, #1D9E75 50%, #38bdf8 100%)',
            borderRadius: '20px', border: 'none', cursor: 'pointer',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            zIndex: 40, boxShadow: '0 8px 28px rgba(15,110,86,0.45)',
            transition: 'all 0.3s cubic-bezier(0.34,1.56,0.64,1)',
            animation: 'pulseGlow 2.5s infinite',
          }}
          onMouseEnter={e => { e.currentTarget.style.transform = 'scale(1.15) rotate(-5deg)'; e.currentTarget.style.boxShadow = '0 12px 36px rgba(15,110,86,0.55)'; }}
          onMouseLeave={e => { e.currentTarget.style.transform = 'scale(1) rotate(0deg)'; e.currentTarget.style.boxShadow = '0 8px 28px rgba(15,110,86,0.45)'; }}
        >
          <Bot size={28} color="white" />
          {chatMessages.filter(m => m.role === 'user').length > 0 && (
            <span style={{ position: 'absolute', top: '-6px', right: '-6px', background: 'linear-gradient(135deg, #f97316, #ef4444)', color: 'white', fontSize: '11px', fontWeight: 800, borderRadius: '50%', width: '22px', height: '22px', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px solid white', animation: 'chatBounce 0.8s ease' }}>
              {Math.min(chatMessages.filter(m => m.role === 'user').length, 9)}
            </span>
          )}
        </button>
      )}
    </div>
  );
};

export default ProductsPage;
